diff --git a/include/nlohmann/detail/input/binary_reader.hpp b/include/nlohmann/detail/input/binary_reader.hpp
index 033cfeb..8c8f4ac 100644
--- a/include/nlohmann/detail/input/binary_reader.hpp
+++ b/include/nlohmann/detail/input/binary_reader.hpp
@@ -790,12 +790,14 @@ class binary_reader
                     {
                         binary_t b;
                         // use binary subtype and store in a binary container
+                        std::uint64_t tag_value = 0;
                         switch (current)
                         {
                             case 0xD8:
                             {
                                 std::uint8_t subtype{};
                                 get_number(input_format_t::cbor, subtype);
+                                tag_value = subtype;
                                 b.set_subtype(detail::conditional_static_cast<typename binary_t::subtype_type>(subtype));
                                 break;
                             }
@@ -803,6 +805,7 @@ class binary_reader
                             {
                                 std::uint16_t subtype{};
                                 get_number(input_format_t::cbor, subtype);
+                                tag_value = subtype;
                                 b.set_subtype(detail::conditional_static_cast<typename binary_t::subtype_type>(subtype));
                                 break;
                             }
@@ -810,6 +813,7 @@ class binary_reader
                             {
                                 std::uint32_t subtype{};
                                 get_number(input_format_t::cbor, subtype);
+                                tag_value = subtype;
                                 b.set_subtype(detail::conditional_static_cast<typename binary_t::subtype_type>(subtype));
                                 break;
                             }
@@ -817,11 +821,24 @@ class binary_reader
                             {
                                 std::uint64_t subtype{};
                                 get_number(input_format_t::cbor, subtype);
+                                tag_value = subtype;
                                 b.set_subtype(detail::conditional_static_cast<typename binary_t::subtype_type>(subtype));
                                 break;
                             }
                             default:
-                                return parse_cbor_internal(true, tag_handler);
+                            {
+                                // embedded tag value (0xC6..0xD4 = tags 6..20) \u2014 outside typed-array range
+                                auto last_token = get_token_string();
+                                return sax->parse_error(chars_read, last_token, parse_error::create(112, chars_read,
+                                                        exception_message(input_format_t::cbor, concat("invalid CBOR tag for typed array: 0x", last_token), "tag"), nullptr));
+                            }
+                        }
+                        // validate tag value is in the typed-array range 64..87 (0x40..0x57)
+                        if (JSON_HEDLEY_UNLIKELY(tag_value < 0x40 || tag_value > 0x57))
+                        {
+                            auto last_token = get_token_string();
+                            return sax->parse_error(chars_read, last_token, parse_error::create(112, chars_read,
+                                                    exception_message(input_format_t::cbor, concat("invalid CBOR typed-array tag value: ", std::to_string(tag_value), "; expected 64..87"), "tag"), nullptr));
+                        }
                         get();
                         return get_cbor_binary(b) && sax->binary(b);
